        // We use a priority queue (min-heap) to process nodes in order of earliest arrival time
        PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[0], b[0]));
        pq.offer(new long[]{0, 0}); // [time, node]
        Map<Long, Long> dist = new HashMap<>();
        dist.put(0, 0);

